"use strict";(globalThis.webpackChunkwebsite_docusaurus=globalThis.webpackChunkwebsite_docusaurus||[]).push([[3915],{6823(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/convocore/","label":"ConvoCore","docId":"index","unlisted":false},{"type":"category","label":"Getting Started","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/convocore/getting-started/quick-start","label":"Quick Start","docId":"getting-started/quick-start","unlisted":false},{"type":"link","href":"/convocore/getting-started/project-structure","label":"Project Structure","docId":"getting-started/project-structure","unlisted":false},{"type":"link","href":"/convocore/getting-started/troubleshooting","label":"Troubleshooting","docId":"getting-started/troubleshooting","unlisted":false}],"href":"/convocore/getting-started/installation"},{"type":"category","label":"Core Systems","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/convocore/core-systems/conversation-data","label":"Conversation Data","docId":"core-systems/conversation-data","unlisted":false},{"type":"link","href":"/convocore/core-systems/conversation-container","label":"Conversation Container","docId":"core-systems/conversation-container","unlisted":false},{"type":"link","href":"/convocore/core-systems/input-modes","label":"Input Modes","docId":"core-systems/input-modes","unlisted":false},{"type":"link","href":"/convocore/core-systems/conversation-state","label":"Conversation State","docId":"core-systems/conversation-state","unlisted":false},{"type":"link","href":"/convocore/core-systems/player-choices","label":"Player Choices","docId":"core-systems/player-choices","unlisted":false},{"type":"link","href":"/convocore/core-systems/line-continuation","label":"Line Continuation","docId":"core-systems/line-continuation","unlisted":false}],"href":"/convocore/core-systems/convocore-component"},{"type":"category","label":"YAML Reference","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/convocore/yaml-reference/yaml-format","label":"YAML Format","docId":"yaml-reference/yaml-format","unlisted":false},{"type":"link","href":"/convocore/yaml-reference/yaml-loading","label":"YAML Loading","docId":"yaml-reference/yaml-loading","unlisted":false}],"href":"/convocore/yaml-reference/yaml-overview"},{"type":"category","label":"Characters","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/convocore/characters/character-representations","label":"Character Representations","docId":"characters/character-representations","unlisted":false},{"type":"link","href":"/convocore/characters/expressions","label":"Expressions","docId":"characters/expressions","unlisted":false}],"href":"/convocore/characters/character-profiles"},{"type":"category","label":"UI","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/convocore/ui/sample-ui","label":"Sample UI","docId":"ui/sample-ui","unlisted":false},{"type":"link","href":"/convocore/ui/building-a-ui","label":"Building a Custom UI","docId":"ui/building-a-ui","unlisted":false},{"type":"link","href":"/convocore/ui/dialogue-history","label":"Dialogue History","docId":"ui/dialogue-history","unlisted":false}],"href":"/convocore/ui/ui-foundation"},{"type":"category","label":"Dialogue Actions","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/convocore/dialogue-actions/built-in-actions","label":"Built-in Actions","docId":"dialogue-actions/built-in-actions","unlisted":false},{"type":"link","href":"/convocore/dialogue-actions/custom-actions","label":"Custom Actions","docId":"dialogue-actions/custom-actions","unlisted":false}],"href":"/convocore/dialogue-actions/actions-overview"},{"type":"category","label":"Localization","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/convocore/localization/adding-languages","label":"Adding Languages","docId":"localization/adding-languages","unlisted":false}],"href":"/convocore/localization/localization-overview"},{"type":"category","label":"Save System","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/convocore/save-system/save-manager","label":"Save Manager","docId":"save-system/save-manager","unlisted":false},{"type":"link","href":"/convocore/save-system/conversation-save-manager","label":"Conversation Save Manager","docId":"save-system/conversation-save-manager","unlisted":false},{"type":"link","href":"/convocore/save-system/variable-store","label":"Variable Store","docId":"save-system/variable-store","unlisted":false},{"type":"link","href":"/convocore/save-system/save-providers","label":"Save Providers","docId":"save-system/save-providers","unlisted":false},{"type":"link","href":"/convocore/save-system/snapshot-migration","label":"Snapshot Migration","docId":"save-system/snapshot-migration","unlisted":false}],"href":"/convocore/save-system/save-system-overview"},{"type":"link","href":"/convocore/settings/convocore-settings","label":"Settings","docId":"settings/convocore-settings","unlisted":false},{"type":"link","href":"/convocore/extending-convocore","label":"Extending ConvoCore","docId":"extending-convocore","unlisted":false}]},"docs":{"characters/character-profiles":{"id":"characters/character-profiles","title":"Character Profiles","description":"A ConvoCoreCharacterProfileBaseData ScriptableObject represents one character in ConvoCore. It defines who the character is, what their display name and color are, and which visual representations they have available. Every character that speaks in a conversation must have a profile.","sidebar":"tutorialSidebar"},"characters/character-representations":{"id":"characters/character-representations","title":"Character Representations","description":"A character representation defines how a character looks for a given dialogue line: their sprite set, 3D prefab, or any other visual configuration. Representations are ScriptableObjects that extend CharacterRepresentationBase.","sidebar":"tutorialSidebar"},"characters/expressions":{"id":"characters/expressions","title":"Expressions","description":"Expressions are named emotional states (Happy, Angry, Surprised, Neutral) that control what a character looks like during a specific dialogue line. Each expression maps to a visual change: a different sprite, an animation trigger, a shader parameter update, or any custom logic you provide.","sidebar":"tutorialSidebar"},"core-systems/conversation-container":{"id":"core-systems/conversation-container","title":"Conversation Container","description":"A ConversationContainer is a ScriptableObject that groups multiple conversations and defines a strategy for selecting which one to play. Rather than hard-coding a single conversation into a runner, you can point the runner at a container and let it decide at runtime, cycling through a pool of NPC greetings, playing a story sequence in order, or choosing dialogue based on weighted probability.","sidebar":"tutorialSidebar"},"core-systems/conversation-data":{"id":"core-systems/conversation-data","title":"Conversation Data","description":"ConvoCoreConversationData is the ScriptableObject that represents a single conversation. It holds the compiled dialogue lines, the participant character profiles, localization data, and a stable identity GUID. It is the core data asset that the ConvoCore runner reads from at runtime.","sidebar":"tutorialSidebar"},"core-systems/conversation-state":{"id":"core-systems/conversation-state","title":"Conversation State","description":"ConvoCore tracks the lifecycle of a running conversation through the ConversationState enum, accessible at any time via the CurrentDialogueState property. Understanding state transitions is important for writing reliable UI code, integrating with other game systems, and avoiding common bugs like double-starting a conversation.","sidebar":"tutorialSidebar"},"core-systems/convocore-component":{"id":"core-systems/convocore-component","title":"ConvoCore Component","description":"The ConvoCore MonoBehaviour is the central piece of the runtime system. Attach it to a GameObject in your scene and it manages all conversation playback: loading dialogue data, advancing lines, running actions, firing events, and coordinating with the UI.","sidebar":"tutorialSidebar"},"core-systems/input-modes":{"id":"core-systems/input-modes","title":"Input Modes","description":"The Input field on the ConvoCore component determines what conversation (or group of conversations) plays when you call PlayConversation() with no arguments. Instead of a fixed reference to one conversation, this field accepts an IConvoInput implementation, a small object that resolves a conversation at the moment PlayConversation() is called.","sidebar":"tutorialSidebar"},"core-systems/line-continuation":{"id":"core-systems/line-continuation","title":"Line Continuation","description":"After ConvoCore displays a dialogue line, it needs to know what to do next. Should it advance to the following line? End the conversation? Jump to a different conversation? Display a set of options for the player? The answer is controlled by the Line Continuation Mode, a field set on each line in the ConvoCoreConversationData inspector, not in the YAML file itself.","sidebar":"tutorialSidebar"},"core-systems/player-choices":{"id":"core-systems/player-choices","title":"Player Choices","description":"When a dialogue line\'s continuation mode is set to PlayerChoice, ConvoCore pauses playback, hands a list of options to your UI, and waits for the player to make a selection. This page covers how to configure choice lines, what each field does, how to implement the UI coroutine that presents the options, and the edge cases you need to handle.","sidebar":"tutorialSidebar"},"dialogue-actions/actions-overview":{"id":"dialogue-actions/actions-overview","title":"Actions Overview","description":"Dialogue actions are the primary way to connect your dialogue to the rest of your game. They are ScriptableObject assets that run game logic in sync with individual lines - before the text appears, or after the player advances. Use them to trigger camera moves, spawn NPCs, play cutscenes, flip quest flags, update analytics, fade portraits in and out, or run any other code your game needs.","sidebar":"tutorialSidebar"},"dialogue-actions/built-in-actions":{"id":"dialogue-actions/built-in-actions","title":"Built-in Actions","description":"ConvoCore ships with six ready-to-use dialogue actions in the SampleActions folder. Each is a ScriptableObject you create as an asset and assign to dialogue lines in the inspector. Create them via Right-click in the Project panel \u2192 Create \u2192 ConvoCore \u2192 Actions \u2192 [Action Name].","sidebar":"tutorialSidebar"},"dialogue-actions/custom-actions":{"id":"dialogue-actions/custom-actions","title":"Custom Actions","description":"Custom dialogue actions let you run any game logic you want in sync with individual dialogue lines. They are ScriptableObject assets that extend BaseDialogueLineAction, so they are reusable across conversations, configurable per-asset in the inspector, and version-controlled like any other project asset.","sidebar":"tutorialSidebar"},"extending-convocore":{"id":"extending-convocore","title":"Extending ConvoCore","description":"ConvoCore is built top-to-bottom for extensibility. Every layer -- dialogue actions, character visuals, UI display, and save storage -- uses abstract base classes or interfaces that you replace or extend without touching the core package. This page maps every extension point and links to the detailed guide for each one.","sidebar":"tutorialSidebar"},"getting-started/installation":{"id":"getting-started/installation","title":"Installation","description":"This page walks you through installing ConvoCore into a Unity project via the Unity Package Manager, verifying the installation, and completing first-time setup.","sidebar":"tutorialSidebar"},"getting-started/project-structure":{"id":"getting-started/project-structure","title":"Project Structure","description":"This page explains how ConvoCore\'s files are organized inside the package itself, where to put your own project files, and how the framework\'s assembly structure works. Understanding this layout will help you avoid common file-placement mistakes and make it easier to navigate the codebase as your project grows.","sidebar":"tutorialSidebar"},"getting-started/quick-start":{"id":"getting-started/quick-start","title":"Quick Start","description":"This guide walks you through creating a simple \u201cHello World\u201d conversation from scratch. By the end you will have a fully wired ConvoCore setup running in a Unity scene, with console log output confirming that lines are advancing correctly. Adding a visible UI is covered in the UI Foundation page; this guide focuses on getting the core logic working first.","sidebar":"tutorialSidebar"},"getting-started/troubleshooting":{"id":"getting-started/troubleshooting","title":"Troubleshooting","description":"This page covers the most common problems encountered when setting up or using ConvoCore, along with their causes and fixes.","sidebar":"tutorialSidebar"},"index":{"id":"index","title":"ConvoCore","description":"ConvoCore is a modular Unity dialogue framework for authoring branching conversations in YAML and playing them back in any genre of game, without locking you into a specific UI, camera setup, or rendering pipeline.","sidebar":"tutorialSidebar"},"localization/adding-languages":{"id":"localization/adding-languages","title":"Adding Languages","description":"This page walks through the full process of adding a new language to your ConvoCore project, from registering the language in settings through testing it at runtime.","sidebar":"tutorialSidebar"},"localization/localization-overview":{"id":"localization/localization-overview","title":"Localization Overview","description":"ConvoCore has a native localization system built directly into the YAML dialogue format. No external localization packages are required. Every dialogue line carries its own translations as a map of language codes to text strings, and the runtime resolves the correct text for the active language at display time.","sidebar":"tutorialSidebar"},"save-system/conversation-save-manager":{"id":"save-system/conversation-save-manager","title":"Conversation Save Manager","description":"ConvoCoreConversationSaveManager is a MonoBehaviour that sits alongside your ConvoCore component on a scene GameObject. It tracks progress for one conversation (or one entry in a ConversationContainer) and feeds the resume context back into the runner automatically when the conversation starts.","sidebar":"tutorialSidebar"},"save-system/save-manager":{"id":"save-system/save-manager","title":"Save Manager","description":"ConvoCoreSaveManager is the central hub of the save system. It owns the active save provider, manages save slots, assembles the full game snapshot, and distributes restored snapshots to all registered conversation savers.","sidebar":"tutorialSidebar"},"save-system/save-providers":{"id":"save-system/save-providers","title":"Save Providers","description":"A save provider handles the actual reading and writing of save data to a storage backend. The provider is decoupled from the rest of the save system behind the IConvoSaveProvider interface, so you can swap storage backends without changing any gameplay code.","sidebar":"tutorialSidebar"},"save-system/save-system-overview":{"id":"save-system/save-system-overview","title":"Save System Overview","description":"The ConvoCore Save System persists conversation progress and game state across play sessions. It is a separate, optional module; the core ConvoCore runner has no hard dependency on it. Drop it in when your project needs durable progress tracking.","sidebar":"tutorialSidebar"},"save-system/snapshot-migration":{"id":"save-system/snapshot-migration","title":"Snapshot Migration","description":"As you develop and ship updates to your game, the structure of your save data may change: new fields added, variables renamed, conversation GUIDs regenerated, or scope assignments altered. ConvoCoreSnapshotMigrator ensures that save files created with an older version of the schema can still be loaded correctly after an update.","sidebar":"tutorialSidebar"},"save-system/variable-store":{"id":"save-system/variable-store","title":"Variable Store","description":"ConvoVariableStore is a ScriptableObject that stores typed, scoped key-value pairs: a lightweight runtime database for gameplay state that dialogue can read and write. It is the bridge between what happens in a conversation and the rest of your game.","sidebar":"tutorialSidebar"},"settings/convocore-settings":{"id":"settings/convocore-settings","title":"ConvoCore Settings","description":"ConvoCoreSettings is a sealed ScriptableObject that controls global ConvoCore configuration. It is the single configuration file for the entire framework. Language support, YAML source resolution order, save system keys, debug logging, and history renderer profiles are all managed here.","sidebar":"tutorialSidebar"},"ui/building-a-ui":{"id":"ui/building-a-ui","title":"Building a Custom UI","description":"ConvoCore includes a ready-made sample UI in the Samples package that demonstrates all of these patterns in a working scene. If you prefer a hands-on starting point over building from scratch, import the Sample UI first and read its code alongside this guide.","sidebar":"tutorialSidebar"},"ui/dialogue-history":{"id":"ui/dialogue-history","title":"Dialogue History","description":"What Is Dialogue History?","sidebar":"tutorialSidebar"},"ui/sample-ui":{"id":"ui/sample-ui","title":"Sample UI","description":"ConvoCore includes a fully working dialogue UI in its Samples package. If you want a real, working display layer to learn from or build on top of rather than creating one from scratch, this is the fastest way to get started.","sidebar":"tutorialSidebar"},"ui/ui-foundation":{"id":"ui/ui-foundation","title":"UI Foundation","description":"What is ConvoCoreUIFoundation?","sidebar":"tutorialSidebar"},"yaml-reference/yaml-format":{"id":"yaml-reference/yaml-format","title":"YAML Format","description":"This page is the complete field reference for ConvoCore\'s YAML dialogue format. Every supported field is documented here with an explanation of its purpose, whether it is required, and examples showing correct usage.","sidebar":"tutorialSidebar"},"yaml-reference/yaml-loading":{"id":"yaml-reference/yaml-loading","title":"YAML Loading","description":"At runtime, ConvoCore needs to find the YAML text for a conversation before it can parse and play it. The ConvoCoreYamlLoader handles this by trying up to four different sources in a configurable priority order. This page explains each source, when to use it, how to configure the load order, and the three loading APIs available to your code.","sidebar":"tutorialSidebar"},"yaml-reference/yaml-overview":{"id":"yaml-reference/yaml-overview","title":"YAML Overview","description":"ConvoCore authors dialogue in YAML - a plain-text format that any editor can open, any version-control system can track, and any writer can read without prior programming experience. This page explains what YAML is, why ConvoCore uses it, and the practical rules you need to follow to write valid dialogue files.","sidebar":"tutorialSidebar"}}}}')}}]);